import { appendFile, mkdir, readFile, writeFile } from "node:fs/promises";
import { existsSync } from "node:fs";
import path from "node:path";

function requireEnv(name) {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function slugify(value) {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48) || "pdlc-task";
}

function extractSection(body, title) {
  const pattern = new RegExp(`^### ${title}\\s*\\n(?<content>[\\s\\S]*?)(?=\\n### |\\n## |$)`, "m");
  const match = body.match(pattern);
  return match?.groups?.content?.trim() || "Not provided.";
}

function commandApproved(commentBody) {
  return commentBody.trim().toLowerCase() === "/approve analysis";
}

function includesCriticalRiskChange(issue) {
  const text = `${issue.title ?? ""}\n${issue.body ?? ""}`.toLowerCase();
  return text.includes("critical") && text.includes("risk");
}

async function replaceInFile(filePath, replacements) {
  let content = await readFile(filePath, "utf8");

  for (const [oldValue, newValue] of replacements) {
    if (!content.includes(oldValue)) {
      throw new Error(`Expected text not found in ${filePath}: ${oldValue}`);
    }

    content = content.replace(oldValue, newValue);
  }

  await writeFile(filePath, content);
}

function renderAnalysisArtifact(issue) {
  const body = issue.body ?? "";

  return `# PDLC Agent Analysis for Issue #${issue.number}

## Issue

${issue.title}

## Business context

${extractSection(body, "Business context")}

## Initial risk

${extractSection(body, "Initial risk guess")}

## Proposed split

1. Product scope and acceptance criteria.
2. Architecture and service impact.
3. Implementation in the sample app.
4. CI, review, QA, security, and documentation evidence.
5. Release monitoring and follow-up issue creation when errors are detected.

## Human approval

The coding step was started by a human comment:

\`\`\`text
/approve analysis
\`\`\`
`;
}

function renderImplementationPlan(issue) {
  return `# Implementation Plan for Issue #${issue.number}

## Branch work

- Create a dedicated agent branch.
- Add PDLC run artifacts under \`pdlc-runs/issue-${issue.number}/\`.
- Update sample app documentation so the normal CI path is triggered.
- Open a pull request linked to the original issue.

## Verification

- Sample App CI must run on the pull request.
- Human reviewer accepts or rejects the PR.
- After merge, release monitoring records a deployment result and may create a follow-up issue.

## Stop conditions

- Missing issue context.
- Failed CI.
- Human rejection in PR review.
- Deployment failure detected by the release monitor.
`;
}

async function ensureGeneratedFeaturesDoc(issue) {
  const filePath = path.join("sample-app", "docs", "agent-generated-features.md");
  await mkdir(path.dirname(filePath), { recursive: true });

  const header = `# Agent Generated Feature Log

This file is intentionally touched by the coding agent MVP so pull requests exercise the sample app CI path.
`;

  const current = existsSync(filePath) ? await readFile(filePath, "utf8") : header;
  const nextEntry = `
## Issue #${issue.number}: ${issue.title}

- Source issue: #${issue.number}
- Generated by: PDLC coding agent MVP
- Scope: documentation-level sample app change used to verify the automated issue to PR loop.
`;

  await writeFile(filePath, `${current.trimEnd()}\n${nextEntry}\n`);
}

async function applyCriticalRiskChange() {
  await replaceInFile("sample-app/dotnet-api/Program.cs", [
    [
      `    {
        >= 14 => "regulated",
        >= 10 => "high",
        >= 6 => "medium",
        _ => "low"
    };`,
      `    {
        >= 90 => "critical",
        >= 14 => "regulated",
        >= 10 => "high",
        >= 6 => "medium",
        _ => "low"
    };`,
    ],
  ]);

  await replaceInFile("sample-app/java-api/src/main/java/com/example/pdlc/RiskScore.java", [
    [
      `        if (total >= 14) {
            return "regulated";
        }`,
      `        if (total >= 90) {
            return "critical";
        }
        if (total >= 14) {
            return "regulated";
        }`,
    ],
  ]);

  await replaceInFile("sample-app/java-api/src/test/java/com/example/pdlc/RiskScoreTest.java", [
    [
      `    @Test
    void classifiesHighRisk() {
        RiskScore score = RiskScore.fromDimensions(2, 2, 2, 2, 1, 1);

        assertEquals(10, score.total());
        assertEquals("high", score.riskClass());
    }
}`,
      `    @Test
    void classifiesHighRisk() {
        RiskScore score = RiskScore.fromDimensions(2, 2, 2, 2, 1, 1);

        assertEquals(10, score.total());
        assertEquals("high", score.riskClass());
    }

    @Test
    void classifiesCriticalRisk() {
        RiskScore score = RiskScore.fromDimensions(15, 15, 15, 15, 15, 15);

        assertEquals(90, score.total());
        assertEquals("critical", score.riskClass());
    }
}`,
    ],
  ]);

  await replaceInFile("sample-app/angular-frontend/src/app/risk-summary.ts", [
    [`export type RiskClass = 'low' | 'medium' | 'high' | 'regulated';`, `export type RiskClass = 'low' | 'medium' | 'high' | 'regulated' | 'critical';`],
    [
      `  if (score >= 14) {
    return 'regulated';
  }`,
      `  if (score >= 90) {
    return 'critical';
  }

  if (score >= 14) {
    return 'regulated';
  }`,
    ],
  ]);

  await replaceInFile("sample-app/angular-frontend/src/app/app.component.ts", [
    [`          <input type="number" [value]="score()" (input)="setScore($event)" min="0" max="18">`, `          <input type="number" [value]="score()" (input)="setScore($event)" min="0" max="100">`],
  ]);
}

async function writeOutput(name, value) {
  const outputPath = requireEnv("GITHUB_OUTPUT");
  await appendFile(outputPath, `${name}<<EOF\n${value}\nEOF\n`);
}

async function main() {
  const event = JSON.parse(await readFile(requireEnv("GITHUB_EVENT_PATH"), "utf8"));
  const issue = event.issue;
  const comment = event.comment;

  if (!issue || issue.pull_request || !comment || !commandApproved(comment.body ?? "")) {
    console.log("No /approve analysis command on a normal issue.");
    return;
  }

  const runId = process.env.GITHUB_RUN_ID ?? Date.now().toString();
  const slug = slugify(issue.title);
  const branch = `agent/issue-${issue.number}-${slug}-${runId}`;
  const runDirectory = path.join("pdlc-runs", `issue-${issue.number}`);

  await mkdir(runDirectory, { recursive: true });
  await writeFile(path.join(runDirectory, "analysis.md"), renderAnalysisArtifact(issue));
  await writeFile(path.join(runDirectory, "implementation-plan.md"), renderImplementationPlan(issue));
  await ensureGeneratedFeaturesDoc(issue);

  const appliesCriticalRiskChange = includesCriticalRiskChange(issue);
  if (appliesCriticalRiskChange) {
    await applyCriticalRiskChange();
  }

  const prTitle = `Agent implementation for issue #${issue.number}`;
  const prBody = `## Summary

- Relates to #${issue.number}
- Adds deterministic PDLC run artifacts for the approved analysis.
- ${appliesCriticalRiskChange ? "Implements critical risk classification in the .NET API, Java API, and Angular frontend." : "Updates the sample app documentation to trigger CI and prove the issue to PR loop."}

## Human approval trail

- Analysis approval command: \`/approve analysis\`
- PR approval remains manual in GitHub.

## Release monitoring

After this PR is merged, the PDLC release monitor workflow records the post-merge result on issue #${issue.number}.`;

  await writeFile(".pdlc-pr-body.md", prBody);
  await writeOutput("branch", branch);
  await writeOutput("commit_message", `Implement agent work for issue #${issue.number}`);
  await writeOutput("pr_title", prTitle);
  console.log(`Prepared agent changes for issue #${issue.number} on ${branch}.`);
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
